"use client";

import * as React from "react";
import { Streamdown } from "streamdown";
import { code } from "@streamdown/code";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

interface ResponseProps extends React.ComponentProps<"div"> {
  /** The markdown content to render */
  children: string;
  /** Whether the content is currently being streamed */
  isAnimating?: boolean;
  /** Animation configuration. true = defaults, or custom options. */
  animated?:
    | boolean
    | {
        animation?: "fadeIn" | "blurIn" | "slideUp";
        duration?: number;
        easing?: string;
        sep?: "word" | "char";
      };
  /** Shiki themes for code highlighting [light, dark] */
  shikiTheme?: [string, string];
  /** Show line numbers in code blocks */
  lineNumbers?: boolean;
  /** Controls configuration for code blocks and tables */
  controls?: {
    code?: boolean | { copy?: boolean; download?: boolean };
    table?:
      | boolean
      | { copy?: boolean; download?: boolean; fullscreen?: boolean };
  };
  /** Called when streaming animation starts */
  onAnimationStart?: () => void;
  /** Called when streaming animation ends */
  onAnimationEnd?: () => void;
}

// =============================================================================
// COMPONENT
// =============================================================================

function Response({
  children,
  isAnimating = false,
  animated = true,
  shikiTheme,
  lineNumbers = true,
  controls,
  className,
  onAnimationStart,
  onAnimationEnd,
  ...props
}: ResponseProps) {
  return (
    <div
      data-slot="response"
      className={cn("prose prose-sm dark:prose-invert max-w-none", className)}
      {...props}
    >
      <Streamdown
        isAnimating={isAnimating}
        animated={animated}
        plugins={{ code }}
        shikiTheme={
          shikiTheme as
            | [import("shiki").BundledTheme, import("shiki").BundledTheme]
            | undefined
        }
        lineNumbers={lineNumbers}
        controls={controls}
        onAnimationStart={onAnimationStart}
        onAnimationEnd={onAnimationEnd}
      >
        {children}
      </Streamdown>
    </div>
  );
}

Response.displayName = "Response";

export { Response };
export type { ResponseProps };
